action:
# I need to get all pages. Let me get more pages and also get albums and playlists.
token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiJzcG90aWZ5K2phYy1ibGFja2J1cm5AZ21haWwuY29tIiwiZXhwIjoxNjg0NDEyMDk4fQ.j-gGvzbEKuMVB7BV4KZqT6OCerRIce5LLeUDmiBL-0I"

# Get all song library pages
all_songs = []
page_index = 0
while True:
    songs_page = apis.spotify.show_song_library(access_token=token, page_index=page_index, page_limit=20)
    if not songs_page:
        break
    all_songs.extend(songs_page)
    page_index += 1

print(f"Song library pages: {page_index}, total songs: {len(all_songs)}")
print(all_songs)

